#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define fr first
#define se second
#define pb push_back
using namespace std;
const int N = 105 , M = 25;
const LL Inf = 0x3f3f3f3f3f3f3f3f;
struct node{LL x,dis;};
bool operator < (const node &A , const node &B){
    return A.dis>B.dis;
}LL n,m,k,E,D,mny[N][N],dis[M],dp[N];vector<pLL> g[M];
bool vis[N][M],flag[M],is[M];priority_queue<node> q;
LL read(){
    LL su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
LL Dijkstra(){
    while(!q.empty())q.pop();
    for(int i=1;i<=m;i++)dis[i]=Inf,is[i]=0;
    q.push({1,0}),dis[1]=0;
    while(!q.empty()){
        auto [u,d]=q.top();q.pop();
        if(is[u])continue;is[u]=1;
        for(auto [v,w]:g[u])if(!flag[v]&&d+w<dis[v])
            dis[v]=d+w,q.push({v,dis[v]});
    }return dis[m];
}
int main(){
    n=read(),m=read(),k=read(),E=read();
    for(int i=1;i<=E;i++){
        LL x=read(),y=read(),z=read();
        g[x].pb({y,z}),g[y].pb({x,z});
    }D=read();for(int i=1;i<=D;i++){
        int p=read(),x=read(),y=read();
        for(int t=x;t<=y;t++)vis[t][p]=1;
    }for(int i=1;i<=n;i++){
        for(int x=1;x<=m;x++)flag[x]=0;
        for(int j=i;j<=n;j++){
            for(int x=1;x<=m;x++)
                if(vis[j][x])flag[x]=1;
            mny[i][j]=Dijkstra();
        }
    }memset(dp,0x3f,sizeof(dp));dp[0]=-k;
    for(int i=1;i<=n;i++)for(int j=0;j<i;j++)
        if(mny[j+1][i]<Inf)dp[i]=min(dp[i],dp[j]+mny[j+1][i]*(i-j)+k);
    cout<<dp[n]<<"\n";
    return 0;
}
